mapper.update:
update wf_hist_order 
set order_State = #{orderState}, 
end_Time = #{endTime}, 
variable = #{variable} 
where id = #{id}

mapper.select:
		select count(o.id) from wf_hist_order o left join wf_process p on p.id = o.process_id


                o.creator in

                    #{operator}



                and p.name in

                    #{name}



                and o.process_Id = #{request.processId}


                and p.type = #{request.processType}



				and p.display_Name like #{pattern} 


                and o.parent_Id = #{request.parentId}


                and o.order_State = #{request.state}


                and o.create_Time >= #{request.createTimeStart}


                and o.create_Time <= #{request.createTimeEnd}


                and o.order_No = #{request.orderNo}

		select o.id, o.process_Id, o.order_State, o.priority, o.creator, o.create_Time, o.end_Time, o.parent_Id,
		o.expire_Time, o.order_No, o.variable 
		from wf_hist_order o left join wf_process p on p.id = o.process_id


                o.creator in

                    #{operator}



                and p.name in

                    #{name}



                and o.process_Id = #{request.processId}


                and p.type = #{request.processType}



				and p.display_Name like #{pattern} 


                and o.parent_Id = #{request.parentId}


                and o.order_State = #{request.state}


                and o.create_Time >= #{request.createTimeStart}


                and o.create_Time <= #{request.createTimeEnd}


                and o.order_No = #{request.orderNo}


		order by #{request.orderBy} #{request.order}
		limit #{rowOffset}, #{request.pageSize}
